const prospects = $input.all().map(i => i.json);
const now = new Date();
const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000);

const total = prospects.length;
const inSequence = prospects.filter(p => p.status === 'in_sequence').length;
const replied = prospects.filter(p => p.replied === 'true' || p.replied === true).length;
const bounced = prospects.filter(p => p.bounced === 'true' || p.bounced === true).length;
const completed = prospects.filter(p => p.status === 'completed').length;
const newProspects = prospects.filter(p => p.status === 'new').length;

// Emails sent today
const sentToday = prospects.filter(p => {
  if (!p.last_sent_at) return false;
  return new Date(p.last_sent_at) >= oneDayAgo;
}).length;

const replyRate = total > 0 ? Math.round((replied / total) * 100) : 0;
const bounceRate = total > 0 ? Math.round((bounced / total) * 100) : 0;

// By campaign
const campaigns = {};
for (const p of prospects) {
  const c = p.campaign || 'default';
  if (!campaigns[c]) campaigns[c] = { total: 0, replied: 0, bounced: 0 };
  campaigns[c].total++;
  if (p.replied === 'true' || p.replied === true) campaigns[c].replied++;
  if (p.bounced === 'true' || p.bounced === true) campaigns[c].bounced++;
}

const campaignSummary = Object.entries(campaigns)
  .map(([name, stats]) => `${name}: ${stats.total} total, ${stats.replied} replied (${Math.round(stats.replied/stats.total*100)}%)`)
  .join('<br>');

// Step distribution
const stepCounts = [0, 0, 0, 0, 0];
for (const p of prospects) {
  const step = parseInt(p.step || '0', 10);
  if (step >= 0 && step <= 4) stepCounts[step]++;
}

return [{
  json: {
    total,
    new_prospects: newProspects,
    in_sequence: inSequence,
    replied,
    bounced,
    completed,
    sent_today: sentToday,
    reply_rate: replyRate,
    bounce_rate: bounceRate,
    campaign_summary: campaignSummary,
    step_distribution: `Not started: ${stepCounts[0]}, Step 1: ${stepCounts[1]}, Step 2: ${stepCounts[2]}, Step 3: ${stepCounts[3]}, Step 4: ${stepCounts[4]}`,
    report_date: now.toISOString().split('T')[0]
  }
}];
